from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.ensemble import RandomForestClassifier
from sklearn.pipeline import Pipeline
import numpy as np
from time import time

def solve(X_train, y_train, X_val, y_val):
    start_time = time()

    # Convert text data to TF-IDF features using CountVectorizer and then use a classifier like RandomForest which can handle sparse matrices.
    pipeline = Pipeline([('tfidf', TfidfVectorizer(stop_words='english')])  # Stop words removal might improve the model performance by focusing on more relevant terms in text data.

    try:
        if time() - start_time > 300:
            raise Exception("Time limit exceeded")

        X_train_processed = pipeline.fit_transform(X_train)
        rf_classifier = RandomForestClassifier(n_estimators=100, class_weight='balanced')  # Using balanced to handle imbalanced classes better if necessary

        try:
            X_val_processed = pipeline.transform(X_val)

            with np.errstate(divide='ignore'):  # To avoid division by zero and warnings in the next steps, ignore them for now (these can be handled later if needed).
                predictions = rf_classifier.predict(X_val_processed)

        except NotFittedError:
            raise Exception("Model not fitted yet")  # Ensure model is trained before predicting

    except NameError as e:
        print(e)
        X_train_processed = TfidfVectorizer().fit_transform(X_train)  # Handle the case where tfidf might fail to import or instantiate.

    if predictions is None:
        raise Exception("Predictions could not be generated")  # Catch and handle prediction generation errors here too

    return np.array(predictions, dtype=int)
